/**
 * Helper to get the image for a product.
 * Falls back to the database image if no manual override exists.
 */
export function getProductImage(productName: string, dbImage: string): string {
  // Priority: Manual Map > Database Image
  return manualImages[productName] || manualImages[productName.toLowerCase()] || dbImage;
}
